def process(x):
    """Clean and normalize a value to a snake_case string."""
    if isinstance(x, str):
        return x.strip().lower().replace(' ', '_')
    return str(x)

result = list(map(process, ["  Hello World ", 42, "  Python  "]))
print(result)  # ['hello_world', '42', 'python']

